import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";

import Header from "../components/common/Header";
import Navbar from "../components/common/Navbar";
import Footer from "../components/common/Footer";

// Các component đã tách
import ProductImages from "../components/product/ProductImages";
import ProductInfo from "../components/product/ProductInfo";
import ProductTabs from "../components/product/ProductTabs";
import RelatedProducts from "../components/product/RelatedProducts";
import ProductSpecs from "../components/product/ProductSpecs";
import ShareButtons from "../components/product/ShareButtons";
import StickyCartBar from "../components/product/StickyCartBar";

const API_BASE = "http://localhost:5000";

const ProductDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();

  // STATES
  const [product, setProduct] = useState(null);
  const [related, setRelated] = useState([]);
  const [reviews, setReviews] = useState([]);

  const [loading, setLoading] = useState(true);
  const [qty, setQty] = useState(1);
  const [selectedImage, setSelectedImage] = useState("");
  const [activeTab, setActiveTab] = useState("description");

  useEffect(() => {
    window.scrollTo(0, 0);
    fetchProduct();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [id]);

  // FETCH PRODUCT DATA
  const fetchProduct = async () => {
    setLoading(true);

    try {
      // ====== 1. LẤY SẢN PHẨM ======
      const res = await fetch(`${API_BASE}/api/products/${id}`);
      const data = await res.json();

      if (data.success) {
        // hỗ trợ cả 2 kiểu: { product } hoặc { data }
        const p = data.product || data.data;
        if (p) {
          setProduct(p);
          setSelectedImage(p.images && p.images[0] ? p.images[0] : "");
        } else {
          setProduct(null);
        }
      } else {
        setProduct(null);
      }

      // ====== 2. LẤY REVIEW ======
      const rv = await fetch(`${API_BASE}/api/reviews/${id}`);
      const rvData = await rv.json();

      if (rvData.success) {
        // hỗ trợ cả { reviews } hoặc { data }
        const rvList = rvData.reviews || rvData.data || [];
        setReviews(Array.isArray(rvList) ? rvList : []);
      } else {
        setReviews([]);
      }

      // ====== 3. LẤY SẢN PHẨM LIÊN QUAN ======
      const rel = await fetch(`${API_BASE}/api/products/${id}/related`);
      const relData = await rel.json();

      if (relData.success) {
        const relList = relData.products || relData.data || [];
        setRelated(Array.isArray(relList) ? relList : []);
      } else {
        setRelated([]);
      }
    } catch (err) {
      console.log("❌ Lỗi lấy chi tiết sản phẩm:", err);
      setProduct(null);
      setReviews([]);
      setRelated([]);
    }

    setLoading(false);
  };

  // CART
  const addToCart = () => {
    if (!product) return;

    const item = {
      _id: product._id,
      name: product.name,
      price: product.discountPrice || product.price,
      image: product.images?.[0] || "",
      qty,
    };

    let cart = JSON.parse(localStorage.getItem("cart") || "[]");

    const exist = cart.find((x) => x._id === item._id);
    if (exist) exist.qty += qty;
    else cart.push(item);

    localStorage.setItem("cart", JSON.stringify(cart));
    alert("Đã thêm vào giỏ hàng!");
  };

  const buyNow = () => {
    addToCart();
    navigate("/cart");
  };

  // LOADING
  if (loading) {
    return (
      <>
        <Header />
        <Navbar />
        <div className="text-center text-pink-600 mt-20 text-xl">
          Đang tải sản phẩm...
        </div>
      </>
    );
  }

  // KHÔNG TÌM THẤY SP
  if (!product) {
    return (
      <>
        <Header />
        <Navbar />
        <div className="text-center text-red-600 mt-20 text-xl">
          Sản phẩm không tồn tại!
        </div>
      </>
    );
  }

  // ================================
  //     UI CHÍNH – ĐÃ RÚT GỌN
  // ================================
  return (
    <>
      <Header />
      <Navbar />

      <div className="min-h-screen bg-[#fff] py-12">
        <div className="max-w-7xl mx-auto px-4">
          {/* Ảnh + Info */}
        <div className="bg-[#fff6f8] rounded-3xl shadow-xl p-10 grid grid-cols-1 md:grid-cols-2 gap-10">
            <ProductImages
              product={product}
              selectedImage={selectedImage}
              setSelectedImage={setSelectedImage}
            />

            <ProductInfo
              product={product}
              qty={qty}
              setQty={setQty}
              addToCart={addToCart}
              buyNow={buyNow}
            />
          </div>

          {/* Tabs Mô tả + Đánh giá */}
          <ProductTabs
            activeTab={activeTab}
            setActiveTab={setActiveTab}
            product={product}
            reviews={reviews}
            
          />
          {/* COMPONENT: Thông tin sản phẩm */}
          <ProductSpecs product={product} />
          <ShareButtons product={product} />
          {/* Sản phẩm liên quan */}
          <RelatedProducts related={related} navigate={navigate} />
        </div>
      </div>
<StickyCartBar
    product={product}
    qty={qty}
    addToCart={addToCart}
    buyNow={buyNow}
/>

<Footer />

      <Footer />
    </>
  );
};

export default ProductDetail;
